#!/bin/bash

# Read JSON and convert to CSV
{
  echo "name,department,salary"
  cat /data/employees.json | tr ',' '\n' | awk '
    /"name"/ { 
      gsub(/.*"name":"/, ""); 
      gsub(/".*/, ""); 
      name = $0 
    }
    /"department"/ { 
      gsub(/.*"department":"/, ""); 
      gsub(/".*/, ""); 
      dept = $0 
    }
    /"salary"/ { 
      gsub(/.*"salary":/, ""); 
      gsub(/[}].*/, ""); 
      salary = $0;
      print name "," dept "," salary
    }
  '
} | tee /data/employees.csv
EOF

