awk '
BEGIN {
    defaults_file = "/config/defaults.ini"
    custom_file = "/config/custom.ini"
    output_file = "/config/merged.ini"

    # Read defaults
    current_section = ""
    while ((getline line < defaults_file) > 0) {
        if (line ~ /^\[/) {
            match(line, /\[([^\]]+)\]/, arr)
            current_section = arr[1]
            sections[current_section] = 1
            section_order[++sec_count] = current_section
        } else if (line ~ /=/ && line !~ /^#/ && line !~ /^[[:space:]]*$/) {
            split(line, parts, "=", seps)
            key = parts[1]
            value = parts[2]
            # Trim whitespace
            sub(/^[[:space:]]+/, "", key)
            sub(/[[:space:]]+$/, "", key)
            sub(/^[[:space:]]+/, "", value)
            sub(/[[:space:]]+$/, "", value)
            defaults[current_section ":" key] = value
            if (!(key in keys[current_section])) {
                keys[current_section][++key_count[current_section]] = key
            }
        }
    }
    close(defaults_file)

    # Read custom
    current_section = ""
    while ((getline line < custom_file) > 0) {
        if (line ~ /^\[/) {
            match(line, /\[([^\]]+)\]/, arr)
            current_section = arr[1]
            if (!(current_section in sections)) {
                sections[current_section] = 1
                section_order[++sec_count] = current_section
            }
        } else if (line ~ /=/ && line !~ /^#/ && line !~ /^[[:space:]]*$/) {
            split(line, parts, "=", seps)
            key = parts[1]
            value = parts[2]
            # Trim whitespace
            sub(/^[[:space:]]+/, "", key)
            sub(/[[:space:]]+$/, "", key)
            sub(/^[[:space:]]+/, "", value)
            sub(/[[:space:]]+$/, "", value)
            custom[current_section ":" key] = value
            if (!(key in keys[current_section])) {
                keys[current_section][++key_count[current_section]] = key
            }
        }
    }
    close(custom_file)

    # Write merged output
    for (i = 1; i <= sec_count; i++) {
        section = section_order[i]
        print "[" section "]" > output_file

        # Collect unique keys for this section
        unique_keys[1] = ""
        unique_count = 0
        for (key_idx = 1; key_idx <= key_count[section]; key_idx++) {
            key = keys[section][key_idx]
            found = 0
            for (j = 1; j <= unique_count; j++) {
                if (unique_keys[j] == key) {
                    found = 1
                    break
                }
            }
            if (!found) {
                unique_keys[++unique_count] = key
            }
        }

        # Output merged values
        for (j = 1; j <= unique_count; j++) {
            key = unique_keys[j]
            if ((section ":" key) in custom) {
                print key "=" custom[section ":" key] > output_file
            } else {
                print key "=" defaults[section ":" key] > output_file
            }
        }
        print "" > output_file
    }
    close(output_file)
}
